#include <stdio.h>
int main() {
    int N, K, M;
    scanf("%d %d %d", &N, &K, &M);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    long long count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            int subsequence[K];
            int index = 0;
            for (int k = i; k <= j; k++) {
                subsequence[index++] = A[k];
            }
            int median = subsequence[K / 2];
            if (median >= M) {
                count++;
            }
        }
    }
    printf("%lld\n", count % (1000000007));
    return 0;
}

