code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const [N, K, M] = readline().split(' ').map(Number);
const A = readline().split(' ').map(Number);
let count = 0;
for (let i = 0; i < N; i++) {
    for (let j = i; j < N; j++) {
        const subsequence = A.slice(i, j + 1);
        if (subsequence.length == K) {
            subsequence.sort((a, b) => a - b);
            const median = subsequence[Math.floor(K / 2)];
            if (median >= M) {
                count++;
            }
        }
    }
}
console.log(count % (1000000007));
